/**
 * ERP local dev: skip init-data permission checks on voucher list toolbar.
 *
 * - `VITE_PERMISSIONS_LOCAL_MODE=true` in `.env` (webpack must inject VITE_* — see webpack.config.js)
 * - Dev server (`import.meta.env.DEV`): enabled unless explicitly `VITE_PERMISSIONS_LOCAL_MODE=false`
 * - Legacy: `VITE_VOUCHER_PERMISSIONS_LOCAL_MODE` (deprecated)
 */
function readPermissionsLocalFlag(): string | undefined {
  return (
    import.meta.env.VITE_PERMISSIONS_LOCAL_MODE ??
    import.meta.env.VITE_VOUCHER_PERMISSIONS_LOCAL_MODE
  );
}

export function isPermissionsLocalModeActive(): boolean {
  const flag = readPermissionsLocalFlag();
  if (flag === 'true') return true;
  if (flag === 'false') return false;
  return import.meta.env.DEV === true;
}

/** @deprecated Use isPermissionsLocalModeActive */
export const isVoucherPermissionsLocalModeActive = isPermissionsLocalModeActive;
